     1→import { useState, useEffect } from 'react';
     2→import { ALL_BORDER_PATHS, BORDER_CATEGORIES } from '../../data/borderManifest';
     3→
     4→interface Props {
     5→  loadBlpDataUrl: (path: string) => Promise<string>;
     6→}
     7→
     8→interface BorderRenderEntry {
     9→  previewUrl: string;
    10→}
    11→
    12→const decodedImageCache = new Map<string, Promise<HTMLImageElement>>();
    13→
    14→function isAtlasNineSlice(img: HTMLImageElement): boolean {
    15→  const ratio = img.width / Math.max(1, img.height);
    16→  return ratio >= 7.25 && ratio <= 8.75 && img.width >= 64 && img.height >= 8;
    17→}
    18→
    19→async function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
    20→  const cached = decodedImageCache.get(url);
    21→  if (cached) return cached;
    22→  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
    23→    const img = new Image();
    24→    img.onload = () => resolve(img);
    25→    img.onerror = () => reject(new Error(`Failed to load image ${url}`));
    26→    img.src = url;
    27→  });
    28→  decodedImageCache.set(url, promise);
    29→  return promise;
    30→}
    31→
    32→function rotateCellClockwise(atlas: HTMLImageElement, cellIndex: number, cellW: number, cellH: number): HTMLCanvasElement {
    33→  const canvas = document.createElement('canvas');
    34→  canvas.width = cellH;
    35→  canvas.height = cellW;
    36→  const ctx = canvas.getContext('2d');
    37→  if (!ctx) return canvas;
    38→  ctx.translate(cellH, 0);
    39→  ctx.rotate(Math.PI / 2);
    40→  ctx.drawImage(atlas, cellIndex * cellW, 0, cellW, cellH, 0, 0, cellW, cellH);
    41→  return canvas;
    42→}
    43→
    44→function drawHorizontallyTiledEdge(
    45→  ctx: CanvasRenderingContext2D,
    46→  tile: HTMLCanvasElement,
    47→  x: number,
    48→  y: number,
    49→  width: number,
    50→  height: number,
    51→) {
    52→  if (width <= 0 || height <= 0) return;
    53→
    54→  let drawn = 0;
    55→  while (drawn < width) {
    56→    const segmentW = Math.min(height, width - drawn);
    57→    const srcW = (segmentW / height) * tile.width;
    58→    ctx.drawImage(tile, 0, 0, srcW, tile.height, x + drawn, y, segmentW, height);
    59→    drawn += segmentW;
    60→  }
    61→}
    62→
    63→function drawVerticallyTiledAtlasEdge(
    64→  ctx: CanvasRenderingContext2D,
    65→  atlas: HTMLImageElement,
    66→  cellIndex: number,
    67→  cellW: number,
    68→  cellH: number,
    69→  x: number,
    70→  y: number,
    71→  width: number,
    72→  height: number,
    73→) {
    74→  if (width <= 0 || height <= 0) return;
    75→
    76→  let drawn = 0;
    77→  while (drawn < height) {
    78→    const segmentH = Math.min(width, height - drawn);
    79→    const srcH = (segmentH / width) * cellH;
    80→    ctx.drawImage(atlas, cellIndex * cellW, 0, cellW, srcH, x, y + drawn, width, segmentH);
    81→    drawn += segmentH;
    82→  }
    83→}
    84→
    85→function renderAtlasBorderPreview(atlas: HTMLImageElement, skipVerticalSides: boolean): string {
    86→  const cssW = 156;
    87→  const cssH = 96;
    88→  const frameSide = 82;
    89→  const frameX = Math.floor((cssW - frameSide) / 2);
    90→  const frameY = Math.floor((cssH - frameSide) / 2);
    91→  const dpr = 2;
    92→  const canvas = document.createElement('canvas');
    93→  canvas.width = cssW * dpr;
    94→  canvas.height = cssH * dpr;
    95→
    96→  const ctx = canvas.getContext('2d');
    97→  if (!ctx) return '';
    98→
    99→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
   100→  ctx.clearRect(0, 0, cssW, cssH);
   101→  ctx.imageSmoothingEnabled = true;
   102→
   103→  const atlasW = atlas.width;
   104→  const atlasH = atlas.height;
   105→  const cellW = atlasW / 8;
   106→  const corner = Math.max(4, Math.floor(Math.min(atlasH * 0.8, frameSide / 3)));
   107→
   108→  const drawCell = (idx: number, x: number, y: number, w: number, h: number) => {
   109→    ctx.drawImage(atlas, idx * cellW, 0, cellW, atlasH, x, y, w, h);
   110→  };
   111→
   112→  drawCell(4, frameX, frameY, corner, corner);
   113→  drawCell(5, frameX + frameSide - corner, frameY, corner, corner);
   114→  drawCell(6, frameX, frameY + frameSide - corner, corner, corner);
   115→  drawCell(7, frameX + frameSide - corner, frameY + frameSide - corner, corner, corner);
   116→
   117→  const edgeH = frameSide - corner * 2;
   118→  if (!skipVerticalSides && edgeH > 0) {
   119→    drawVerticallyTiledAtlasEdge(ctx, atlas, 0, cellW, atlasH, frameX, frameY + corner, corner, edgeH);
   120→    drawVerticallyTiledAtlasEdge(ctx, atlas, 1, cellW, atlasH, frameX + frameSide - corner, frameY + corner, corner, edgeH);
   121→  }
   122→
   123→  const edgeW = frameSide - corner * 2;
   124→  if (edgeW > 0) {
   125→    const topRot = rotateCellClockwise(atlas, 2, cellW, atlasH);
   126→    const bottomRot = rotateCellClockwise(atlas, 3, cellW, atlasH);
   127→    drawHorizontallyTiledEdge(ctx, topRot, frameX + corner, frameY, edgeW, corner);
   128→    drawHorizontallyTiledEdge(ctx, bottomRot, frameX + corner, frameY + frameSide - corner, edgeW, corner);
   129→  }
   130→
   131→  return canvas.toDataURL('image/png');
   132→}
   133→
   134→function isCinematicBorder(path: string): boolean {
   135→  return path.toLowerCase().includes('cinematic');
   136→}
   137→
   138→async function buildBorderPreview(path: string, rawUrl: string): Promise<string> {
   139→  const img = await loadDataUrlImage(rawUrl);
   140→  if (!isAtlasNineSlice(img)) return rawUrl;
   141→  return renderAtlasBorderPreview(img, isCinematicBorder(path)) || rawUrl;
   142→}
   143→
   144→export default function BordersSection(props: Props) {
   145→  const [rendered, setRendered] = useState<Record<string, BorderRenderEntry>>({});
   146→  const [loading, setLoading] = useState(true);
   147→
   148→  useEffect(() => {
   149→    let cancelled = false;
   150→    void (async () => {
   151→      const results = await Promise.all(
   152→        ALL_BORDER_PATHS.map(async (path) => {
   153→          try {
   154→            const rawUrl = await props.loadBlpDataUrl(path);
   155→            const previewUrl = await buildBorderPreview(path, rawUrl);
   156→            return [path, { previewUrl }] as const;
   157→          } catch (e) {
   158→            console.warn(`[BordersSection] failed to load ${path}`, e);
   159→            return null;
   160→          }
   161→        }),
   162→      );
   163→      if (cancelled) return;
   164→      const map: Record<string, BorderRenderEntry> = {};
   165→      for (const r of results) {
   166→        if (r) map[r[0]] = r[1];
   167→      }
   168→      setRendered(map);
   169→      setLoading(false);
   170→    })();
   171→    return () => { cancelled = true; };
   172→  }, []);
   173→
   174→  return (
   175→    <div className="tab-content">
   176→      <div className="section-card">
   177→        <h2>Border Textures</h2>
   178→        <p className="section-desc">
   179→          All {ALL_BORDER_PATHS.length} border BLP textures across {BORDER_CATEGORIES.length} categories.
   180→          These 9-slice atlases, bar borders, and panel borders define the chrome around every UI element.
   181→        </p>
   182→        {loading ? (
   183→          <div className="borders-loading">Decoding border textures…</div>
   184→        ) : (
   185→          BORDER_CATEGORIES.map((cat) => (
   186→            <div key={cat.title} className="borders-category">
   187→              <h4 className="borders-category-title">{cat.title}</h4>
   188→              <p className="borders-category-desc">{cat.desc}</p>
   189→              <div className="borders-grid">
   190→                {cat.entries.map((entry) => {
   191→                  const image = rendered[entry.path];
   192→                  return image ? (
   193→                    <div key={entry.path} className="border-item">
   194→                      <img className="border-thumbnail" src={image.previewUrl} alt={entry.label} />
   195→                      <div className="border-label">{entry.label}</div>
   196→                    </div>
   197→                  ) : null;
   198→                })}
   199→              </div>
   200→            </div>
   201→          ))
   202→        )}
   203→      </div>
   204→    </div>
   205→  );
   206→}
